SELECT COUNT(DISTINCT S.PK_SIAPE) AS QTD FROM SERVIDOR S JOIN CALC_HORA_AULA_MEDIA CH ON CH.SIAPE = S.PK_SIAPE WHERE LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(S.SIGLA_CAMPUS) = LOWER('for') AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%matem%') OR LOWER(CH.AREA_INGRESSO) LIKE LOWER('%matem%')) AND CH.ANO = 2023 AND CH.SEMESTRE = 2